```class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size();
        vector<int> dp(n, 0);
        for (int i = k; i < n; i++) {
            if (arr[i - k] > arr[i]) {
                dp[i] = dp[i - k] + 1;
            }
        }
        return accumulate(dp.begin(), dp.end(), 0);
    }
};```
